#include<bits/stdc++.h>
using namespace std;
const int K = (1<<6)+5 , mod = 1e9+7;
int n,m,t,num[K],dp[105][K][K][25],ans;
int Count(int x){int cnt=0;while(x)cnt+=(x&1),x>>=1;return cnt;}
int main(){
    cin>>n>>m>>t;
    for(int i=0;i<(1<<n);i++)num[i]=Count(i),dp[1][0][i][num[i]]=1;
    for(int x=2;x<=m;x++)
        for(int i=0;i<(1<<n);i++)for(int c=num[i];c<=t;c++)
            for(int j=0;j<(1<<n);j++)for(int k=0;k<(1<<n);k++){
                if((i&(k>>2))||(k&(j<<2))||(k&(j>>2)))continue;
                if((i&(j<<1))||(i&(j>>1))||(i&(k<<2)))continue;
                dp[x][k][i][c]=(dp[x][k][i][c]+dp[x-1][j][k][c-num[i]])%mod;
            }
    for(int i=0;i<(1<<n);i++)
        for(int j=0;j<(1<<n);j++)ans=(ans+dp[m][i][j][t])%mod;
    cout<<ans<<"\n";
    return 0;
}
